changeSet.sql:
CREATE UNIQUE INDEX IF NOT EXISTS uq_equipment_item_vanilla_slug
    ON public.equipment_item USING btree (slug) WHERE (homebrew_id IS NULL);

CREATE UNIQUE INDEX IF NOT EXISTS uq_feat_vanilla_slug
    ON public.feat USING btree (slug) WHERE (homebrew_id IS NULL);

CREATE UNIQUE INDEX IF NOT EXISTS uq_magic_item_vanilla_slug
    ON public.magic_item USING btree (slug) WHERE (homebrew_id IS NULL);

CREATE UNIQUE INDEX IF NOT EXISTS uq_species_vanilla_slug
    ON public.species USING btree (slug) WHERE (homebrew_id IS NULL);

CREATE UNIQUE INDEX IF NOT EXISTS uq_spell_vanilla_slug
    ON public.spell USING btree (slug) WHERE (homebrew_id IS NULL);

CREATE UNIQUE INDEX IF NOT EXISTS uq_subclass_vanilla_slug
    ON public.subclass USING btree (class_id, slug) WHERE (homebrew_id IS NULL);

rollback.sql:
DROP INDEX IF EXISTS uq_equipment_item_vanilla_slug;
DROP INDEX IF EXISTS uq_feat_vanilla_slug;
DROP INDEX IF EXISTS uq_magic_item_vanilla_slug;
DROP INDEX IF EXISTS uq_species_vanilla_slug;
DROP INDEX IF EXISTS uq_spell_vanilla_slug;
DROP INDEX IF EXISTS uq_subclass_vanilla_slug;
